=Generate a blog topic based on these categories and tags:

Categories: {{ JSON.stringify($json.categories) }}

Tags: {{ JSON.stringify($json.tags) }}

Choose a category and 1-3 relevant tags, then create an engaging topic that combines them in an interesting way. Make sure to use actual IDs from the provided data.

parameters.jsCode:
// Parse the AI response to extract topic data
let content = $input.first().json.message?.content || $input.first().json.text || $input.first().json;

// Handle if content is a string (JSON)
if (typeof content === 'string') {
  // Remove markdown code blocks if present
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  try {
    content = JSON.parse(content);
  } catch (e) {
    // If parsing fails, create a default structure
    content = {
      topic: content,
      searchQueries: [content],
      targetCategoryId: 1,
      targetTagIds: [1],
      angle: "General overview",
      targetAudience: "General readers"
    };
  }
}

return [{ json: content }];

