// Extract research content and citations from Perplexity response
const response = $input.first().json;
const topicData = $('Parse Topic Response1').first().json;

let researchContent = '';
let citations = [];

if (response.choices && response.choices[0]) {
  researchContent = response.choices[0].message?.content || '';
}

if (response.citations) {
  citations = response.citations;
}

return [{
  json: {
    ...topicData,
    research: researchContent,
    citations: citations,
    researchedAt: new Date().toISOString(),
    blocks:$('Merge1').last().json.data.blocks
  }
}];

// Format the article with enhanced blocks for the blog API
const enhancedContent = $input.first().json.message?.content;
const originalArticle = $('Write Article1').first().json.message?.content;
const topicData = $('Parse Research1').first().json;

let blocks = enhancedContent?.blocks || originalArticle?.blocks || [];
let excerpt = originalArticle?.excerpt || '';

// Get title from topic
let title = topicData.topic;

// Generate slug from title
const slug = title
  .toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .substring(0, 100);

// Create content structure
const content = {
  blocks: blocks,
  version: "1.0"
};

return [{
  json: {
    title: title,
    slug: slug,
    postType: 'blog',
    excerpt: excerpt,
    content: JSON.stringify(content),
    coverImage: '',
    published: false,
    publishedAt: null,
    categoryIds: topicData.targetCategoryId ? [topicData.targetCategoryId] : [],
    tagIds: topicData.targetTagIds || [],
    customFields: {
      generatedAt: new Date().toISOString(),
      researchSources: JSON.stringify(topicData.citations || []),
      aiEnhanced: true,
      imageCount: blocks.filter(b => b.type === 'columns').length
    },
    // Keep metadata for email
    _metadata: {
      topic: topicData.topic,
      angle: topicData.angle,
      targetAudience: topicData.targetAudience
    }
  }
}];

// Prepare email notification data
const postResponse = $input.first().json;
const formatData = $('Format for API1').first().json;

// Extract post ID and construct URL
const postId = postResponse.id || postResponse.post?.id || 'unknown';
const postSlug = postResponse.slug || formatData.slug;

// Construct the review URL (adjust domain as needed)
const baseUrl = 'http://localhost:3000';
const reviewUrl = `${baseUrl}/admin/posts/${postId}/edit`;
const previewUrl = `${baseUrl}/blog/${postSlug}`;

return [{
  json: {
    postId: postId,
    title: formatData.title,
    slug: postSlug,
    excerpt: formatData.excerpt,
    reviewUrl: reviewUrl,
    previewUrl: previewUrl,
    metadata: formatData._metadata,
    imageCount: formatData.customFields.imageCount,
    createdAt: new Date().toISOString()
  }
}];

// Parse image suggestions
let imageSuggestions = $input.first().json.message?.content;

if (typeof imageSuggestions === 'string') {
  imageSuggestions = imageSuggestions.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  try {
    imageSuggestions = JSON.parse(imageSuggestions);
  } catch (e) {
    imageSuggestions = { images: [] };
  }
}

const images = imageSuggestions.images || [];

// Output each image as a separate item for parallel processing
return images.map((img, index) => ({
  json: {
    ...img,
    imageIndex: index,
    totalImages: images.length
  }
}));

// Download image from DALL-E URL
// Handle both n8n OpenAI node output and direct URL responses
const inputData = $input.first().json;
const imageUrl = inputData.data?.[0]?.url || inputData.url || null;

if (!imageUrl) {
  throw new Error('No image URL found in DALL-E response. Got: ' + JSON.stringify(inputData));
}

// Fetch the image
const response = await fetch(imageUrl);
if (!response.ok) {
  throw new Error(`Failed to fetch image: ${response.status} ${response.statusText}`);
}

const buffer = await response.arrayBuffer();

// Generate filename
const timestamp = Date.now();
const random = Math.random().toString(36).substring(2, 11);
const filename = `ai-generated-${timestamp}-${random}.png`;

// Get metadata from Parse Image Suggestions
const suggestionData = $('Parse Image Suggestions1').item.json;

return [{
  json: {
    filename: filename,
    mimeType: 'image/png',
    altText: suggestionData.altText,
    caption: suggestionData.caption,
    insertAfterBlock: suggestionData.insertAfterBlock,
    purpose: suggestionData.purpose
  },
  binary: {
    data: {
      data: Buffer.from(buffer).toString('base64'),
      mimeType: 'image/png',
      fileName: filename
    }
  }
}];

// Collect all generated images with their metadata
const allItems = $input.all();

// Get corresponding data from Upload to S3 and Download Image
const images = allItems.map((item, index) => {
  const uploadData = $('Upload to S').all()[index]?.json?.data;
  const downloadData = $('Download Image1').all()[index]?.json;

  return {
    insertAfterBlock: downloadData?.insertAfterBlock || 0,
    url: uploadData?.url || '',
    altText: downloadData?.altText || '',
    caption: downloadData?.caption || '',
    purpose: downloadData?.purpose || ''
  };
});

return [{
  json: {
    images: images,
    imageCount: images.length,
    processedAt: new Date().toISOString()
  }
}];
